my_list = [10, 20, 30]

# What "for x in my_list" actually does:
iterator = iter(my_list)       # calls my_list.__iter__()
while True:
    try:
        x = next(iterator)     # calls iterator.__next__()
        print(x)
    except StopIteration:
        break

class Countdown:
    def __init__(self, start):
        self.current = start

    def __iter__(self):
        return self  # Iterator returns itself

    def __next__(self):
        if self.current <= 0:
            raise StopIteration
        value = self.current
        self.current -= 1
        return value

for n in Countdown(5):
    print(n)  # 5, 4, 3, 2, 1

def read_lines(filename):
    """Stage 1: Source — yields lines from a file one at a time"""
    with open(filename) as f:
        for line in f:
            yield line.rstrip('\n')

def filter_comments(lines):
    """Stage 2: Filter — skip comment lines"""
    for line in lines:
        if not line.startswith('#'):
            yield line

def parse_csv_row(lines):
    """Stage 3: Transform — split each line into fields"""
    for line in lines:
        yield line.split(',')

def take(n, iterable):
    """Stage 4: Limit — yield only the first n items"""
    for i, item in enumerate(iterable):
        if i >= n:
            break
        yield item

