import json
import itertools

def stream_jsonl(filepath):
    """Yield one JSON object per line from a .jsonl file"""
    with open(filepath, encoding='utf-8') as f:
        for line in f:
            line = line.strip()
            if line:
                yield json.loads(line)

def filter_valid(records, min_length=10):
    """Drop records with too-short text"""
    for record in records:
        if len(record.get('text', '')) >= min_length:
            yield record

def tokenize(records, max_tokens=512):
    """Simulate tokenization and truncation"""
    for record in records:
        tokens = record['text'].split()[:max_tokens]
        yield {'tokens': tokens, 'label': record.get('label', 0)}

def batch(iterable, size):
    """Group items into fixed-size batches"""
    it = iter(iterable)
    while True:
        chunk = list(itertools.islice(it, size))
        if not chunk:
            break
        yield chunk

# Build the full pipeline — nothing executes yet
